import bcrypt from 'bcryptjs';
import jwt from 'jsonwebtoken';
import { pool } from '../config/database';
import { env } from '../config/env';
import { AuthUser, JwtPayload, UpdateProfileDto } from '../models/types';

export class AuthService {
  async login(email: string, password: string): Promise<{ token: string; user: AuthUser }> {
    const result = await pool.query(
      `SELECT id, name, email, role, password_hash AS "passwordHash"
       FROM users WHERE email = $1`,
      [email],
    );

    const user = result.rows[0];
    if (!user || !user.passwordHash) {
      throw { status: 401, errors: [{ message: 'Invalid email or password' }] };
    }

    const isValid = await bcrypt.compare(password, user.passwordHash);
    if (!isValid) {
      throw { status: 401, errors: [{ message: 'Invalid email or password' }] };
    }

    const payload: JwtPayload = {
      userId: user.id,
      email: user.email,
      role: user.role,
    };

    const token = jwt.sign(payload, env.jwtSecret, {
      expiresIn: env.jwtExpiresIn,
    });

    return {
      token,
      user: { id: user.id, name: user.name, email: user.email, role: user.role },
    };
  }

  async getMe(userId: string): Promise<AuthUser> {
    const result = await pool.query(
      `SELECT id, name, email, role FROM users WHERE id = $1`,
      [userId],
    );

    if (!result.rows[0]) {
      throw { status: 404, errors: [{ message: 'User not found' }] };
    }

    return result.rows[0];
  }

  async updateProfile(userId: string, dto: UpdateProfileDto): Promise<AuthUser> {
    // If changing password, verify current password first
    if (dto.newPassword) {
      if (!dto.currentPassword) {
        throw { status: 400, errors: [{ message: 'Current password is required to change password', field: 'currentPassword' }] };
      }

      const result = await pool.query(
        `SELECT password_hash AS "passwordHash" FROM users WHERE id = $1`,
        [userId],
      );

      if (!result.rows[0]) {
        throw { status: 404, errors: [{ message: 'User not found' }] };
      }

      const isValid = await bcrypt.compare(dto.currentPassword, result.rows[0].passwordHash);
      if (!isValid) {
        throw { status: 400, errors: [{ message: 'Current password is incorrect', field: 'currentPassword' }] };
      }
    }

    const setClauses: string[] = [];
    const params: unknown[] = [];
    let paramIndex = 1;

    if (dto.name) {
      setClauses.push(`name = $${paramIndex++}`);
      params.push(dto.name);
    }

    if (dto.email) {
      // Check uniqueness
      const existing = await pool.query(
        `SELECT id FROM users WHERE email = $1 AND id != $2`,
        [dto.email, userId],
      );
      if (existing.rows.length > 0) {
        throw { status: 400, errors: [{ message: 'Email is already in use', field: 'email' }] };
      }
      setClauses.push(`email = $${paramIndex++}`);
      params.push(dto.email);
    }

    if (dto.newPassword) {
      const hash = await bcrypt.hash(dto.newPassword, 12);
      setClauses.push(`password_hash = $${paramIndex++}`);
      params.push(hash);
    }

    if (setClauses.length === 0) {
      return this.getMe(userId);
    }

    setClauses.push(`updated_at = NOW()`);
    params.push(userId);

    const result = await pool.query(
      `UPDATE users SET ${setClauses.join(', ')}
       WHERE id = $${paramIndex}
       RETURNING id, name, email, role`,
      params,
    );

    return result.rows[0];
  }
}

import { Request, Response, NextFunction } from 'express';
import jwt from 'jsonwebtoken';
import { env } from '../config/env';
import { JwtPayload } from '../models/types';

// Extend Express Request to include authenticated user
declare global {
  namespace Express {
    interface Request {
      user?: JwtPayload;
    }
  }
}

export const authenticate = (req: Request, res: Response, next: NextFunction): void => {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    res.status(401).json({ errors: [{ message: 'Authentication required' }] });
    return;
  }

  const token = authHeader.slice(7);

  try {
    const payload = jwt.verify(token, env.jwtSecret) as JwtPayload;
    req.user = payload;
    next();
  } catch {
    res.status(401).json({ errors: [{ message: 'Invalid or expired token' }] });
  }
};

import { Request, Response, NextFunction } from 'express';
import { AuthService } from '../services/auth.service';

const authService = new AuthService();

export class AuthController {
  static async login(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      const { email, password } = req.body;

      if (!email || !password) {
        res.status(400).json({
          errors: [{ message: 'Email and password are required' }],
        });
        return;
      }

      const result = await authService.login(email, password);
      res.json({ data: result });
    } catch (error: unknown) {
      const err = error as { status?: number; errors?: unknown[] };
      if (err.status) {
        res.status(err.status).json({ errors: err.errors });
        return;
      }
      next(error);
    }
  }

  static async getMe(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      if (!req.user) {
        res.status(401).json({ errors: [{ message: 'Authentication required' }] });
        return;
      }

      const user = await authService.getMe(req.user.userId);
      res.json({ data: user });
    } catch (error: unknown) {
      const err = error as { status?: number; errors?: unknown[] };
      if (err.status) {
        res.status(err.status).json({ errors: err.errors });
        return;
      }
      next(error);
    }
  }

  static async updateProfile(req: Request, res: Response, next: NextFunction): Promise<void> {
    try {
      if (!req.user) {
        res.status(401).json({ errors: [{ message: 'Authentication required' }] });
        return;
      }

      const { name, email, currentPassword, newPassword } = req.body;
      const user = await authService.updateProfile(req.user.userId, {
        name,
        email,
        currentPassword,
        newPassword,
      });
      res.json({ data: user });
    } catch (error: unknown) {
      const err = error as { status?: number; errors?: unknown[] };
      if (err.status) {
        res.status(err.status).json({ errors: err.errors });
        return;
      }
      next(error);
    }
  }
}

